#requires -Modules Pester
# Workflow / integration tests. Each test case sets up a temp git repo with
# the project files + a per-case fixture, runs `act push --rm` once, captures
# output, appends to act-result.txt, and asserts on exact expected values
# parsed from the run's log.
#
# act is invoked at most 3 times (one per fixture case).

BeforeAll {
    $script:RepoRoot = $PSScriptRoot
    $script:ResultFile = Join-Path $RepoRoot 'act-result.txt'
    if (Test-Path $script:ResultFile) { Remove-Item $script:ResultFile -Force }

    function Invoke-ActCase {
        param(
            [Parameter(Mandatory)] [string] $CaseName,
            [Parameter(Mandatory)] [string] $FixtureRelPath,
            [Parameter(Mandatory)] [string] $Format,
            [Parameter(Mandatory)] [string] $Now,
            [string] $FailOnExpired = 'false'
        )

        # Build an isolated temp git repo containing project files + fixture.
        $work = Join-Path ([System.IO.Path]::GetTempPath()) ("act-srv-" + [guid]::NewGuid().ToString('N'))
        New-Item -ItemType Directory -Path $work | Out-Null
        try {
            Copy-Item -Path (Join-Path $script:RepoRoot 'SecretRotationValidator.ps1') -Destination $work
            Copy-Item -Path (Join-Path $script:RepoRoot 'SecretRotationValidator.Tests.ps1') -Destination $work
            Copy-Item -Path (Join-Path $script:RepoRoot '.actrc') -Destination $work -ErrorAction SilentlyContinue
            Copy-Item -Path (Join-Path $script:RepoRoot '.github') -Destination $work -Recurse
            Copy-Item -Path (Join-Path $script:RepoRoot 'fixtures') -Destination $work -Recurse

            Push-Location $work
            try {
                git init -q -b main
                git -c user.email=t@t -c user.name=t add -A | Out-Null
                git -c user.email=t@t -c user.name=t commit -q -m init | Out-Null

                $envArgs = @(
                    '--env', "TEST_CONFIG_PATH=$FixtureRelPath",
                    '--env', "TEST_FORMAT=$Format",
                    '--env', "TEST_NOW=$Now",
                    '--env', 'TEST_WINDOW_DAYS=14',
                    '--env', "TEST_FAIL_ON_EXPIRED=$FailOnExpired"
                )
                $log = & act push --rm @envArgs 2>&1 | Out-String
                $exit = $LASTEXITCODE

                # Append a clearly delimited block to the shared result file.
                $delim = "===== CASE: $CaseName (exit=$exit) ====="
                Add-Content -Path $script:ResultFile -Value @"
$delim
$log
===== END CASE: $CaseName =====

"@
                return [pscustomobject]@{
                    CaseName = $CaseName
                    ExitCode = $exit
                    Log      = $log
                }
            } finally {
                Pop-Location
            }
        } finally {
            Remove-Item -Recurse -Force $work -ErrorAction SilentlyContinue
        }
    }
}

Describe 'Workflow file structure' {
    BeforeAll {
        $script:WorkflowPath = Join-Path $PSScriptRoot '.github/workflows/secret-rotation-validator.yml'
        # Naive YAML check using regex-ish pattern matching keeps us free of
        # external dependencies; the deeper validation comes from actionlint below.
        $script:WorkflowText = Get-Content -Raw $script:WorkflowPath
    }

    It 'exists at the expected path' {
        Test-Path $script:WorkflowPath | Should -BeTrue
    }

    It 'declares push, pull_request, schedule, and workflow_dispatch triggers' {
        $script:WorkflowText | Should -Match '(?m)^\s*push:'
        $script:WorkflowText | Should -Match '(?m)^\s*pull_request:'
        $script:WorkflowText | Should -Match '(?m)^\s*schedule:'
        $script:WorkflowText | Should -Match '(?m)^\s*workflow_dispatch:'
    }

    It 'defines the unit-tests and validate jobs with a dependency' {
        $script:WorkflowText | Should -Match '(?m)^\s*unit-tests:'
        $script:WorkflowText | Should -Match '(?m)^\s*validate:'
        $script:WorkflowText | Should -Match 'needs:\s*unit-tests'
    }

    It 'references the script file paths that exist' {
        $script:WorkflowText | Should -Match 'SecretRotationValidator\.ps1'
        $script:WorkflowText | Should -Match 'SecretRotationValidator\.Tests\.ps1'
        Test-Path (Join-Path $PSScriptRoot 'SecretRotationValidator.ps1') | Should -BeTrue
        Test-Path (Join-Path $PSScriptRoot 'SecretRotationValidator.Tests.ps1') | Should -BeTrue
    }

    It 'uses actions/checkout@v4' {
        $script:WorkflowText | Should -Match 'actions/checkout@v4'
    }

    It 'passes actionlint cleanly' {
        $null = & actionlint $script:WorkflowPath
        $LASTEXITCODE | Should -Be 0
    }
}

Describe 'Workflow execution via act' {
    Context 'Case 1: all-ok fixture with NOW=2026-05-08 (no expired/warning)' {
        BeforeAll {
            $script:case1 = Invoke-ActCase -CaseName 'all-ok' `
                -FixtureRelPath 'fixtures/all-ok.json' -Format 'json' -Now '2026-05-08'
        }
        It 'act exits 0' { $script:case1.ExitCode | Should -Be 0 }
        It 'both jobs succeed' {
            ($script:case1.Log | Select-String -Pattern 'Job succeeded' -AllMatches).Matches.Count |
                Should -BeGreaterOrEqual 2
        }
        It 'reports total=2 expired=0 warning=0 ok=2' {
            $script:case1.Log | Should -Match 'SUMMARY total=2 expired=0 warning=0 ok=2'
        }
    }

    Context 'Case 2: mixed fixture as JSON with NOW=2026-05-08' {
        BeforeAll {
            $script:case2 = Invoke-ActCase -CaseName 'mixed-json' `
                -FixtureRelPath 'fixtures/mixed.json' -Format 'json' -Now '2026-05-08'
        }
        It 'act exits 0' { $script:case2.ExitCode | Should -Be 0 }
        It 'both jobs succeed' {
            ($script:case2.Log | Select-String -Pattern 'Job succeeded' -AllMatches).Matches.Count |
                Should -BeGreaterOrEqual 2
        }
        It 'reports total=3 expired=1 warning=1 ok=1' {
            $script:case2.Log | Should -Match 'SUMMARY total=3 expired=1 warning=1 ok=1'
        }
        It 'JSON output contains the expected secret names in the right buckets' {
            $script:case2.Log | Should -Match '"name":\s*"db-password"'
            $script:case2.Log | Should -Match '"urgency":\s*"expired"'
            $script:case2.Log | Should -Match '"urgency":\s*"warning"'
            $script:case2.Log | Should -Match '"urgency":\s*"ok"'
        }
    }

    Context 'Case 3: mixed fixture as markdown with NOW=2026-05-08' {
        BeforeAll {
            $script:case3 = Invoke-ActCase -CaseName 'mixed-markdown' `
                -FixtureRelPath 'fixtures/mixed.json' -Format 'markdown' -Now '2026-05-08'
        }
        It 'act exits 0' { $script:case3.ExitCode | Should -Be 0 }
        It 'both jobs succeed' {
            ($script:case3.Log | Select-String -Pattern 'Job succeeded' -AllMatches).Matches.Count |
                Should -BeGreaterOrEqual 2
        }
        It 'reports total=3 expired=1 warning=1 ok=1' {
            $script:case3.Log | Should -Match 'SUMMARY total=3 expired=1 warning=1 ok=1'
        }
        It 'markdown contains expired/warning/ok section headers and the db-password row' {
            $script:case3.Log | Should -Match '## Expired \(1\)'
            $script:case3.Log | Should -Match '## Warning \(1\)'
            $script:case3.Log | Should -Match '## OK \(1\)'
            $script:case3.Log | Should -Match 'db-password'
            $script:case3.Log | Should -Match 'billing, api'
        }
    }
}

Describe 'act-result.txt artifact' {
    It 'exists after the run' {
        Test-Path $script:ResultFile | Should -BeTrue
    }
    It 'contains a delimiter for each case' {
        $text = Get-Content -Raw $script:ResultFile
        $text | Should -Match '===== CASE: all-ok'
        $text | Should -Match '===== CASE: mixed-json'
        $text | Should -Match '===== CASE: mixed-markdown'
    }
}

