#requires -Modules Pester
# Workflow / integration tests. Each test case sets up a temp git repo with
# the project files + a per-case fixture, runs `act push --rm` once, captures
# output, appends to act-result.txt, and asserts on exact expected values
# parsed from the run's log.
#
# act is invoked at most 3 times (one per fixture case).

BeforeAll {
    $script:RepoRoot = $PSScriptRoot
    $script:ResultFile = Join-Path $RepoRoot 'act-result.txt'
    if (Test-Path $script:ResultFile) { Remove-Item $script:ResultFile -Force }

    function Invoke-ActCase {
        param(
            [Parameter(Mandatory)] [string] $CaseName,
            [Parameter(Mandatory)] [string] $FixtureRelPath,
            [Parameter(Mandatory)] [string] $Format,
            [Parameter(Mandatory)] [string] $Now,
            [string] $FailOnExpired = 'false'
        )

        # Build an isolated temp git repo containing project files + fixture.
        $work = Join-Path ([System.IO.Path]::GetTempPath()) ("act-srv-" + [guid]::NewGuid().ToString('N'))
        New-Item -ItemType Directory -Path $work | Out-Null
        try {
            Copy-Item -Path (Join-Path $script:RepoRoot 'SecretRotationValidator.ps1') -Destination $work
            Copy-Item -Path (Join-Path $script:RepoRoot 'SecretRotationValidator.Tests.ps1') -Destination $work
            Copy-Item -Path (Join-Path $script:RepoRoot '.actrc') -Destination $work -ErrorAction SilentlyContinue
            Copy-Item -Path (Join-Path $script:RepoRoot '.github') -Destination $work -Recurse
            Copy-Item -Path (Join-Path $script:RepoRoot 'fixtures') -Destination $work -Recurse

            Push-Location $work
            try {
                git init -q -b main
                git -c user.email=t@t -c user.name=t add -A | Out-Null
                git -c user.email=t@t -c user.name=t commit -q -m init | Out-Null

                $envArgs = @(
                    '--env', "TEST_CONFIG_PATH=$FixtureRelPath",
                    '--env', "TEST_FORMAT=$Format",
                    '--env', "TEST_NOW=$Now",
                    '--env', 'TEST_WINDOW_DAYS=14',
                    '--env', "TEST_FAIL_ON_EXPIRED=$FailOnExpired"
                )
                $log = & act push --rm @envArgs 2>&1 | Out-String
                $exit = $LASTEXITCODE

                # Append a clearly delimited block to the shared result file.
                $delim = "===== CASE: $CaseName (exit=$exit) ====="
                Add-Content -Path $script:ResultFile -Value @"
$delim
$log
===== END CASE: $CaseName =====

"@
                return [pscustomobject]@{
                    CaseName = $CaseName
                    ExitCode = $exit
                    Log      = $log
                }
            } finally {
                Pop-Location
            }
        } finally {
            Remove-Item -Recurse -Force $work -ErrorAction SilentlyContinue
        }
    }
}

